const PROCESSING_FEE = 5;

interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

export const quote = (
  customer: { yearsWithMHPCO: number },
  items: Item[],
  isFollowUp: boolean
): number => {
  const premium = items.reduce((sum, item) => sum + basePremium(item), 0);
  return premium + PROCESSING_FEE;
};

