const componentBlockPremium = (type, count) =>
  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
                                                                        // 2 bindings, 1 conditional (ternary), 1 conditional (??)

const itemsPremium = (items) => {
  const components: Item[] = [];                                        // 1 binding, 1 assignment, 1 constant ([])
  const nonComponents: Item[] = [];                                     // 1 binding, 1 assignment, 1 constant ([])
  for (const item of items) {                                           // 1 loop, 1 binding
    (isComponent(item) ? components : nonComponents).push(item);        // 1 invocation (isComponent), 1 conditional, 1 invocation (push)
  }

