19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	
23	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
24	
25	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
26	
27	const itemPremium = (item: Item): number => {
28	  const base = basePremium(item);
29	  const curseSurcharge = item.cursed ? base * 0.5 : 0;
30	  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
31	  return base + curseSurcharge + enchantmentSurcharge;
32	};
33	
34	const componentBlockPremium = (type: string, count: number): number =>
35	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
36	
37	const itemsPremium = (items: Item[]): number => {
38	  const components: Item[] = [];
39	  const nonComponents: Item[] = [];
40	  for (const item of items) {
41	    (isComponent(item) ? components : nonComponents).push(item);
42	  }
43	
44	  const counts: Record<string, number> = {};
45	  for (const item of components) {
46	    counts[item.type] = (counts[item.type] ?? 0) + 1;
47	  }
48	
49	  const mainPremium = nonComponents.reduce(
50	    (sum, item) => sum + itemPremium(item),
51	    0
52	  );
53	  const componentTotal = Object.entries(counts).reduce(
54	    (sum, [type, count]) => sum + componentBlockPremium(type, count),
55	    0
56	  );
57	  return mainPremium + componentTotal;
58	};
59	
60	export const quote = (
61	  customer: { yearsWithMHPCO: number },
62	  items: Item[],
63	  isFollowUp: boolean
64	): number => {
65	  const premium = itemsPremium(items);
66	  return premium + PROCESSING_FEE;
67	};
