import { describe, it, expect } from "vitest";
import { quote } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote - base premiums", () => {
    it("returns 5G processing fee for empty item list", () => {
      const result = quote({ yearsWithMHPCO: 0 }, [], false);
      expect(result).toBe(5);
    });
    it("returns base premium plus fee for a single sword (100 + 5 = 105)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        false
      );
      expect(result).toBe(105);
    });
    it("returns base premium plus fee for a single amulet (60 + 5 = 65)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        false
      );
      expect(result).toBe(65);
    });
    it("returns base premium plus fee for a single staff (80 + 5 = 85)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "staff", material: "oak", enchantment: 0, cursed: false }],
        false
      );
      expect(result).toBe(85);
    });
    it("returns base premium plus fee for a single potion (40 + 5 = 45)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        false
      );
      expect(result).toBe(45);
    });
    it("sums base premiums for multiple items plus fee", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "sword", material: "steel", enchantment: 0, cursed: false },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
        false
      );
      expect(result).toBe(165);
    });
  });

  describe("quote - component premiums", () => {
    it("returns 25G base premium per component (e.g. 2 runes = 50)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
        ],
        false
      );
      expect(result).toBe(55);
    });
    it("applies block discount for exactly 3 alike components (3 runes = 60)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
        ],
        false
      );
      expect(result).toBe(65);
    });
    it("does not apply block for 4 alike components (4 runes = 100)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
        ],
        false
      );
      expect(result).toBe(105);
    });
    it("does not apply block for 3 components of different types (2 runes + 1 moonstone = 75)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
        ],
        false
      );
      expect(result).toBe(80);
    });
    it("applies separate blocks for 3 runes and 3 moonstones (120)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
          { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
          { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
        ],
        false
      );
      expect(result).toBe(125);
    });
  });

  describe("quote - item-level modifiers", () => {
    it("adds 50% cursed surcharge to the cursed item's base premium only", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "sword", material: "steel", enchantment: 0, cursed: true },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
        false
      );
      // sword base 100 + curse 50 + amulet base 60 = 210 + 5 fee = 215
      // (policy modifiers not yet applied in this test)
      expect(result).toBe(215);
    });
    it("adds 30% high-enchantment surcharge for enchantment level >= 5", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        false
      );
      expect(result).toBe(135);
    });
    it("applies both cursed and high-enchantment surcharges to the same item", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
        false
      );
      // 100 base + 50 curse + 30 enchantment + 5 fee = 185
      expect(result).toBe(185);
    });
    it("does not apply high-enchantment surcharge for enchantment level 4", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
        false
      );
      expect(result).toBe(105);
    });
  });

  describe("quote - policy-level modifiers", () => {
    it("applies 10% first-insurance surcharge on the policy base premium", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        false
      );
      // 100 base + 10 first-insurance (10% of 100) + 5 fee = 115
      expect(result).toBe(115);
    });
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("applies 15% follow-up discount on second quote");
    it.todo("applies first-insurance surcharge even for long-standing customers");
  });

  describe("quote - rounding", () => {
    it.todo("rounds premium up in MHPCO's favor (ceiling)");
  });

  describe("quote - integration", () => {
    it.todo("newcomer with cursed sword: 165G");
    it.todo("long-standing customer second contract with cursed high-enchantment sword: 160G");
  });

  describe("claim - basic payout", () => {
    it.todo("applies 100G deductible per damaged item");
    it.todo("fully reimburses dragon-material item damage minus deductible");
    it.todo("reimburses at 50% for enchantment >= 8 then applies deductible");
    it.todo("applies 50% rule when both dragon material and enchantment >= 8");
    it.todo("does not apply enchantment clause for enchantment < 8");
  });

  describe("claim - cap", () => {
    it.todo("caps total payout at twice the insurance sum");
    it.todo("tracks remaining cap across successive claims on same policy");
  });

  describe("claim - multiple items", () => {
    it.todo("applies deductible separately per damaged item in same event");
    it.todo("handles damage to component (rune) with deductible");
  });

  describe("claim - rounding", () => {
    it.todo("rounds payout down in MHPCO's favor (floor)");
  });

  describe("error handling", () => {
    it.todo("rejects unknown item type in quote");
    it.todo("rejects claim for item not in policy");
    it.todo("rejects claim with more damage entries than insured items of that type");
    it.todo("rejects negative damage amount");
  });

  describe("CLI integration", () => {
    it.todo("reads scenario JSON from stdin and writes results JSON to stdout");
    it.todo("processes sequential quote and claim steps referencing policy by index");
  });
});

