import { describe, it, expect } from "vitest";
import { quote } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote - base premiums", () => {
    it("returns 5G processing fee for empty item list", () => {
      const result = quote({ yearsWithMHPCO: 0 }, [], false);
      expect(result).toBe(5);
    });
    it("returns base premium plus fee for a single sword (100 + 5 = 105)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        false
      );
      expect(result).toBe(115);
    });
    it("returns base premium plus fee for a single amulet (60 + 5 = 65)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        false
      );
      expect(result).toBe(71);
    });
    it("returns base premium plus fee for a single staff (80 + 5 = 85)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "staff", material: "oak", enchantment: 0, cursed: false }],
        false
      );
      expect(result).toBe(93);
    });
    it("returns base premium plus fee for a single potion (40 + 5 = 45)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        false
      );
      expect(result).toBe(49);
    });
    it("sums base premiums for multiple items plus fee", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "sword", material: "steel", enchantment: 0, cursed: false },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
        false
      );
      expect(result).toBe(181);
    });
  });

  describe("quote - component premiums", () => {
    it("returns 25G base premium per component (e.g. 2 runes = 50)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
        ],
        false
      );
      expect(result).toBe(60);
    });
    it("applies block discount for exactly 3 alike components (3 runes = 60)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
        ],
        false
      );
      expect(result).toBe(73);
    });
    it("does not apply block for 4 alike components (4 runes = 100)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
        ],
        false
      );
      expect(result).toBe(115);
    });
    it("does not apply block for 3 components of different types (2 runes + 1 moonstone = 75)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
        ],
        false
      );
      expect(result).toBe(88);
    });
    it("applies separate blocks for 3 runes and 3 moonstones (120)", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "rune", material: "stone", enchantment: 0, cursed: false },
          { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
          { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
          { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
        ],
        false
      );
      expect(result).toBe(140);
    });
  });

  describe("quote - item-level modifiers", () => {
    it("adds 50% cursed surcharge to the cursed item's base premium only", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [
          { type: "sword", material: "steel", enchantment: 0, cursed: true },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
        false
      );
      // sword base 100 + curse 50 + amulet base 60 = 210 + 16 first-ins (10% of 160) + 5 fee = 231
      expect(result).toBe(231);
    });
    it("adds 30% high-enchantment surcharge for enchantment level >= 5", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        false
      );
      expect(result).toBe(145);
    });
    it("applies both cursed and high-enchantment surcharges to the same item", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
        false
      );
      // 100 base + 50 curse + 30 enchantment + 10 first-ins + 5 fee = 195
      expect(result).toBe(195);
    });
    it("does not apply high-enchantment surcharge for enchantment level 4", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
        false
      );
      expect(result).toBe(115);
    });
  });

  describe("quote - policy-level modifiers", () => {
    it("applies 10% first-insurance surcharge on the policy base premium", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        false
      );
      // 100 base + 10 first-insurance (10% of 100) + 5 fee = 115
      expect(result).toBe(115);
    });
    it("applies 20% loyalty discount for customer with >= 2 years", () => {
      const result = quote(
        { yearsWithMHPCO: 3 },
        [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        false
      );
      // 100 base + 10 first-ins - 20 loyalty + 5 fee = 95
      expect(result).toBe(95);
    });
    it("applies 15% follow-up discount on second quote", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        true
      );
      // 100 base + 10 first-ins - 15 follow-up + 5 fee = 100
      expect(result).toBe(100);
    });
    it("applies first-insurance surcharge even for long-standing customers", () => {
      const result = quote(
        { yearsWithMHPCO: 3 },
        [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        true
      );
      // 100 base + 10 first-ins - 20 loyalty - 15 follow-up + 5 fee = 80
      expect(result).toBe(80);
    });
  });

  describe("quote - rounding", () => {
    it("rounds premium up in MHPCO's favor (ceiling)", () => {
      const result = quote(
        { yearsWithMHPCO: 2 },
        [{ type: "rune", material: "stone", enchantment: 0, cursed: false }],
        false
      );
      // 25 item + 2.5 first-ins - 5 loyalty + 5 fee = 27.5 → ceil = 28
      expect(result).toBe(28);
    });
  });

  describe("quote - integration", () => {
    it("newcomer with cursed sword: 165G", () => {
      const result = quote(
        { yearsWithMHPCO: 0 },
        [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        false
      );
      // 100 base + 50 curse + 10 first-ins + 5 fee = 165
      expect(result).toBe(165);
    });
    it.todo("long-standing customer second contract with cursed high-enchantment sword: 160G");
  });

  describe("claim - basic payout", () => {
    it.todo("applies 100G deductible per damaged item");
    it.todo("fully reimburses dragon-material item damage minus deductible");
    it.todo("reimburses at 50% for enchantment >= 8 then applies deductible");
    it.todo("applies 50% rule when both dragon material and enchantment >= 8");
    it.todo("does not apply enchantment clause for enchantment < 8");
  });

  describe("claim - cap", () => {
    it.todo("caps total payout at twice the insurance sum");
    it.todo("tracks remaining cap across successive claims on same policy");
  });

  describe("claim - multiple items", () => {
    it.todo("applies deductible separately per damaged item in same event");
    it.todo("handles damage to component (rune) with deductible");
  });

  describe("claim - rounding", () => {
    it.todo("rounds payout down in MHPCO's favor (floor)");
  });

  describe("error handling", () => {
    it.todo("rejects unknown item type in quote");
    it.todo("rejects claim for item not in policy");
    it.todo("rejects claim with more damage entries than insured items of that type");
    it.todo("rejects negative damage amount");
  });

  describe("CLI integration", () => {
    it.todo("reads scenario JSON from stdin and writes results JSON to stdout");
    it.todo("processes sequential quote and claim steps referencing policy by index");
  });
});

const PROCESSING_FEE = 5;

interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const itemPremium = (item: Item): number => {
  const base = basePremium(item);
  const curseSurcharge = item.cursed ? base * 0.5 : 0;
  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
  return base + curseSurcharge + enchantmentSurcharge;
};

const componentBlockPremium = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);

const countByType = (items: Item[]): Record<string, number> =>
  items.reduce<Record<string, number>>((counts, item) => {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
    return counts;
  }, {});

const itemsPremium = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const nonComponents = items.filter((item) => !isComponent(item));

  const mainPremium = nonComponents.reduce(
    (sum, item) => sum + itemPremium(item),
    0
  );
  const componentTotal = Object.entries(countByType(components)).reduce(
    (sum, [type, count]) => sum + componentBlockPremium(type, count),
    0
  );
  return mainPremium + componentTotal;
};

export const quote = (
  customer: { yearsWithMHPCO: number },
  items: Item[],
  isFollowUp: boolean
): number => {
  const premium = itemsPremium(items);
  const policyBasePremium = items.reduce((sum, item) => sum + basePremium(item), 0);
  const firstInsurance = policyBasePremium * 0.1;
  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
  const followUpDiscount = isFollowUp ? policyBasePremium * 0.15 : 0;
  return Math.ceil(premium + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
};

