const INSURANCE_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const DEDUCTIBLE = 100;
const HIGH_ENCHANTMENT_THRESHOLD = 8;
const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;

const isHighEnchantment = (item: Item | undefined): boolean =>
  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const reimbursableAmount = (policyItem: Item | undefined, damageAmount: number): number =>
  isHighEnchantment(policyItem)
    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
    : damageAmount;

const insuranceValue = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;

const totalInsuranceValue = (items: Item[]): number =>
  items.reduce((sum, item) => sum + insuranceValue(item), 0);

export const claim = (
  policy: { items: Item[] },
  damages: { itemType: string; amount: number }[],
  remainingCap?: number
): { payout: number; remainingCap: number } => {
  const cap = remainingCap ?? totalInsuranceValue(policy.items) * 2;
  const uncappedPayout = damages.reduce((sum, damage) => {
    const policyItem = policy.items.find((item) => item.type === damage.itemType);
    const reimbursement = reimbursableAmount(policyItem, damage.amount);
    return sum + Math.max(0, reimbursement - DEDUCTIBLE);
  }, 0);
  const payout = Math.min(uncappedPayout, cap);
  return { payout, remainingCap: cap - payout };
};

