import { quote } from "./claim-office.js";

const input = await new Promise<string>((resolve) => {
  let data = "";
  process.stdin.setEncoding("utf-8");
  process.stdin.on("data", (chunk) => (data += chunk));
  process.stdin.on("end", () => resolve(data));
});

const scenario = JSON.parse(input);
const results = scenario.steps.map((step: { op: string; items: unknown[] }) => {
  if (step.op === "quote") {
    const isFollowUp = scenario.steps.indexOf(step) > 0 &&
      scenario.steps.slice(0, scenario.steps.indexOf(step)).some((s: { op: string }) => s.op === "quote");
    return { premium: quote(scenario.customer, step.items as never[], isFollowUp) };
  }
  return {};
});

process.stdout.write(JSON.stringify({ results }));

